export function getSistemaArticleBySlug(slug) {
  return sistemaArticles.find((article) => article.slug === slug);
}

export function getAdjacentSistemaArticles(slug) {
  const currentIndex = sistemaArticles.findIndex((article) => article.slug === slug);
  if (currentIndex === -1) {
    return { previous: null, next: null };
  }
  return {
    previous: sistemaArticles[(currentIndex - 1 + sistemaArticles.length) % sistemaArticles.length],
    next: sistemaArticles[(currentIndex + 1) % sistemaArticles.length],
  };
}
